      {
        "@type": "Question",
        "name": "What irradiance sensor class does IEC 61724-1 require for solar DAS commissioning?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "IEC 61724-1:2021 Class A monitoring systems require ISO 9060:2018 Class A pyranometers for GHI, POA, and DHI measurements. Class B pyranometers are permitted for Class B monitoring. PV reference cells fail the ±3% uncertainty threshold for both classes; field data shows them running 2–4% higher than ISO-classified pyranometers."
        }
      },
